    25→function getDayOfYear(date = new Date()) {
    26→	const start = new Date(Date.UTC(date.getFullYear(), 0, 1));
    27→	const current = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
    28→
    29→	return Math.floor((current.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1;
    30→}
    31→
    32→function getHarmonicsByObservationsCount({
    33→	observations,
    34→}: {
    35→	observations: number;
    36→}): number {
    37→	if (observations <= 800) return 8;
    38→	return 4;
    39→}
