    41→function generateDateRange(startDate: string, endDate: string, count: number): string[] {
    42→	const start = new Date(startDate);
    43→	const end = new Date(endDate);
    44→	const totalDays =
    45→		Math.floor((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1;
    46→	const step = totalDays / count;
    47→
    48→	const dates: string[] = [];
    49→	for (let i = 0; i < count; i++) {
    50→		const currentDate = new Date(start.getTime() + i * step * 24 * 60 * 60 * 1000);
    51→		const dateArr = currentDate.toISOString().split('T') as [string, string];
    52→		dates.push(dateArr[0]);
    53→	}
    54→	return dates;
    55→}
    56→
    57→function generateFutureDates(endDate: string, forecastDays: number): string[] {
    58→	const dates: string[] = [];
    59→	const startDate = new Date(endDate);
    60→
    61→	for (let i = 1; i <= forecastDays; i++) {
    62→		const futureDate = new Date(startDate);
    63→		futureDate.setDate(startDate.getDate() + i);
    64→		const dateArr = futureDate.toISOString().split('T') as [string, string];
    65→		dates.push(dateArr[0]);
    66→	}
    67→
    68→	return dates;
    69→}
    70→
    71→function calculateSeasonalComponent({
    72→	values,
    73→	period,
    74→	harmonics,
    75→}: {
    76→	values: number[];
    77→	period: number;
    78→	harmonics: number;
    79→}): number[] {
    80→	const n = values.length;
    81→	if (n < period) {
    82→		return new Array(n).fill(0) as number[];
    83→	}
    84→
    85→	try {
    86→		const coefficients = MathematicalFunctions.fourierCoefficients({
    87→			values,
    88→			period,
    89→			harmonics,
    90→			precision: null,
    91→		});
    92→
    93→		const seasonal = MathematicalFunctions.reconstructFourierSeries({
    94→			period,
    95→			harmonics,
    96→			a: coefficients.a,
    97→			b: coefficients.b,
    98→			length: n,
    99→		});
   100→
   101→		return seasonal;
   102→	} catch {
   103→		return values.map((_, index) => {
   104→			const cyclePosition = index % Math.max(1, Math.floor(period));
   105→			const seasonalIndex = Math.min(cyclePosition, values.length - 1);
   106→			return values[seasonalIndex] ? values[seasonalIndex] * 0.1 : 0;
   107→		});
   108→	}
   109→}
   110→
   111→function calculateTrendComponent({
   112→	values,
   113→	changePoints,
   114→	startDate,
   115→	endDate,
   116→}: {
   117→	values: number[];
   118→	changePoints: number[];
   119→	startDate: string;
   120→	endDate: string;
   121→}): number[] {
   122→	const n = values.length;
   123→	if (n === 0) return [];
   124→
   125→	const dates = generateDateRange(startDate, endDate, n);
   126→
   127→	if (changePoints.length === 0) {
   128→		return MathematicalFunctions.calculateTrend({ values, dates });
   129→	}
   130→
   131→	const trend = new Array(n).fill(0) as number[];
   132→	const segments = [0, ...changePoints, n];
   133→
   134→	for (let i = 0; i < segments.length - 1; i++) {
   135→		const start = segments[i] as unknown as number;
   136→		const end = segments[i + 1] as unknown as number;
   137→		const segmentValues = values.slice(start, end);
   138→		const segmentDates = dates.slice(start, end);
   139→
   140→		if (segmentValues.length > 1) {
   141→			const segmentTrend = MathematicalFunctions.calculateTrend({
   142→				values: segmentValues,
   143→				dates: segmentDates,
   144→			});
   145→
   146→			for (let j = 0; j < segmentTrend.length; j++) {
   147→				trend[start + j] = segmentTrend[j] as unknown as number;
   148→			}
   149→		} else if (segmentValues.length === 1) {
   150→			trend[start] = segmentValues[0] as unknown as number;
   151→		}
   152→	}
   153→
   154→	return trend;
   155→}
   156→
   157→function extendSeasonalComponent(
   158→	component: number[],
   159→	period: number,
   160→	harmonics: number,
   161→	historicalLength: number,
   162→	forecastDates: string[],
   163→	endDate: string,
   164→): number[] {
   165→	if (component.length === 0) return Array(forecastDates.length).fill(0) as number[];
   166→
   167→	try {
   168→		const coefficients = MathematicalFunctions.fourierCoefficients({
   169→			values: component,
   170→			period,
   171→			harmonics,
   172→			precision: null,
   173→		});
   174→
   175→		const forecastValues: number[] = [];
   176→		const endDateObj = new Date(endDate);
   177→
   178→		for (const forecastDate of forecastDates) {
   179→			const forecastDateObj = new Date(forecastDate);
   180→
   181→			const daysDiff = Math.floor(
   182→				(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
   183→			);
   184→
   185→			const cyclePosition = (historicalLength + daysDiff) % period;
   186→			const singlePointSeries = MathematicalFunctions.reconstructFourierSeries({
   187→				period,
   188→				harmonics,
   189→				a: coefficients.a,
   190→				b: coefficients.b,
   191→				length: Math.ceil(cyclePosition) + 1,
   192→				a0: 0,
   193→			});
   194→
   195→			const seasonalValue = singlePointSeries[Math.floor(cyclePosition)] ?? 0;
   196→			forecastValues.push(seasonalValue);
   197→		}
   198→
   199→		return forecastValues;
   200→	} catch {
   201→		return forecastDates.map((forecastDate) => {
   202→			const endDateObj = new Date(endDate);
   203→			const forecastDateObj = new Date(forecastDate);
   204→			const daysDiff = Math.floor(
   205→				(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
   206→			);
   207→			const flooredPeriod = Math.max(1, Math.floor(period));
   208→			const cyclePosition = (historicalLength + daysDiff) % flooredPeriod;
   209→			const historicalIndex = Math.min(cyclePosition, component.length - 1);
   210→			return component[historicalIndex] ?? 0;
   211→		});
   212→	}
   213→}
   214→
   215→function extendTrendComponent(trendComponent: number[], forecastDays: number): number[] {
   216→	if (trendComponent.length < 2) return Array(forecastDays).fill(0) as number[];
   217→
   218→	const recentTrendPoints = Math.min(30, trendComponent.length);
   219→	const recentTrend = trendComponent.slice(-recentTrendPoints);
   220→
   221→	const x = Array.from({ length: recentTrend.length }, (_, i) => i);
   222→	const regression = MathematicalFunctions.linearRegression({ x, y: recentTrend });
   223→
   224→	const lastValue = trendComponent[trendComponent.length - 1] ?? 0;
   225→	const trendSlope = regression.slope;
   226→
   227→	return Array(forecastDays)
   228→		.fill(0)
   229→		.map((_, i) => {
   230→			const decay = Math.exp(-0.02 * i);
   231→			return lastValue + trendSlope * (i + 1) * decay;
   232→		});
   233→}
   234→
   235→function extendResidualsComponent({
   236→	smoothedResidualsArr,
   237→	forecastDays,
   238→	endDate,
   239→}: {
   240→	smoothedResidualsArr: number[];
   241→	forecastDays: number;
   242→	endDate: string;
   243→}): number[] {
   244→	if (smoothedResidualsArr.length === 0 || forecastDays <= 0) {
   245→		return Array(forecastDays).fill(0) as number[];
   246→	}
   247→
   248→	const twoWeeksLength = 7;
   249→	const trendLength = Math.min(twoWeeksLength, smoothedResidualsArr.length);
   250→	const recentResiduals = smoothedResidualsArr.slice(-trendLength);
   251→
   252→	const endDateObj = new Date(endDate);
   253→	const dates = recentResiduals.map((_, i) => {
   254→		const date = new Date(endDateObj);
   255→		date.setDate(endDateObj.getDate() - (trendLength - i - 1));
   256→		const dateArr = date.toISOString().split('T') as [string, string];
   257→		return dateArr[0];
   258→	});
   259→
   260→	const trendValues = MathematicalFunctions.calculateTrend({
   261→		values: recentResiduals,
   262→		dates,
   263→	});
   264→
   265→	if (trendValues.length === 0) {
   266→		return Array(forecastDays).fill(0) as number[];
   267→	}
   268→
   269→	const x = Array.from({ length: recentResiduals.length }, (_, i) => i);
   270→	const regression = MathematicalFunctions.linearRegression({ x, y: recentResiduals });
   271→
   272→	const lastIndex = recentResiduals.length - 1;
   273→	return Array(forecastDays)
   274→		.fill(0)
   275→		.map((_, i) => {
   276→			return regression.slope * (lastIndex + i + 1) + regression.intercept;
   277→		});
   278→}
   279→
   280→function createComprehensiveForecast({
   281→	yearlyComponent,
   282→	monthlyComponent,
   283→	weeklyComponent,
   284→	quarterlyComponent,
   285→	trendComponent,
   286→	smoothedResidualsArr,
   287→	historicalLength,
   288→	forecastDays,
   289→	endDate,
   290→}: {
   291→	yearlyComponent: number[];
   292→	monthlyComponent: number[];
   293→	weeklyComponent: number[];
   294→	quarterlyComponent: number[];
   295→	trendComponent: number[];
   296→	smoothedResidualsArr: number[];
   297→	historicalLength: number;
   298→	forecastDays: number;
   299→	endDate: string;
   300→	purchasesArr: number[];
   301→}) {
   302→	const forecastDates = generateFutureDates(endDate, forecastDays);
   303→
   304→	const harmonics = getHarmonicsByObservationsCount({
   305→		observations: historicalLength,
   306→	});
   307→
   308→	const extendedYearly = extendSeasonalComponent(
   309→		yearlyComponent,
   310→		365,
   311→		harmonics,
   312→		historicalLength,
   313→		forecastDates,
   314→		endDate,
   315→	);
   316→	const extendedMonthly = extendSeasonalComponent(
   317→		monthlyComponent,
   318→		30,
   319→		harmonics,
   320→		historicalLength,
   321→		forecastDates,
   322→		endDate,
   323→	);
   324→	const extendedWeekly = extendSeasonalComponent(
   325→		weeklyComponent,
   326→		7,
   327→		harmonics,
   328→		historicalLength,
   329→		forecastDates,
   330→		endDate,
   331→	);
   332→	const extendedQuarterly = extendSeasonalComponent(
   333→		quarterlyComponent,
   334→		91,
   335→		harmonics,
   336→		historicalLength,
   337→		forecastDates,
   338→		endDate,
   339→	);
   340→
   341→	const extendedResiduals = extendResidualsComponent({
   342→		smoothedResidualsArr,
   343→		forecastDays,
   344→		endDate,
   345→	});
   346→
   347→	const extendedTrend = extendTrendComponent(trendComponent, forecastDays);
   348→
   349→	const forecastValues = Array(forecastDays)
   350→		.fill(0)
   351→		.map((_, i) => {
   352→			const yearly = extendedYearly[i] ?? 0;
   353→			const monthly = extendedMonthly[i] ?? 0;
   354→			const weekly = extendedWeekly[i] ?? 0;
   355→			const quarterly = extendedQuarterly[i] ?? 0;
   356→			const trend = extendedTrend[i] ?? 0;
   357→			const residual = extendedResiduals[i] ?? 0;
   358→			const forecastValue = trend + yearly + monthly + weekly + quarterly + residual;
   359→			return Math.max(0, forecastValue);
   360→		});
   361→
   362→	return {
   363→		forecastValues,
   364→		forecastDates,
   365→		components: {
   366→			yearly: extendedYearly,
   367→			monthly: extendedMonthly,
   368→			weekly: extendedWeekly,
   369→			quarterly: extendedQuarterly,
   370→			trend: extendedTrend,
   371→			residuals: extendedResiduals,
   372→		},
   373→	};
   374→}
