   376→function forecastStyleTrend({
   377→	styleId,
   378→	historicalData,
   379→	startDate,
   380→	endDate,
   381→	forecastDays,
   382→}: {
   383→	styleId: number;
   384→	historicalData: IProductAnnualSalesBase[];
   385→	startDate: string;
   386→	endDate: string;
   387→	forecastDays: number;
   388→}): CompleteForecastResult | null {
   389→	try {
   390→		const startDateObj = new Date(startDate);
   391→		const endDateObj = new Date(endDate);
   392→		const startYear = startDateObj.getFullYear();
   393→		const endYear = endDateObj.getFullYear();
   394→		const endDateDayNumber = getDayOfYear(endDateObj);
   395→
   396→		const totalExpectedDays =
   397→			Math.floor(
   398→				(endDateObj.getTime() - startDateObj.getTime()) / (1000 * 60 * 60 * 24),
   399→			) + 1;
   400→
   401→		const dataByYear = new Map<number, number[]>();
   402→		for (const data of historicalData) {
   403→			dataByYear.set(data.year, data.daily_orders);
   404→		}
   405→
   406→		const purchasesArr: number[] = [];
   407→
   408→		for (let year = startYear; year <= endYear; year++) {
   409→			const yearData = dataByYear.get(year);
   410→
   411→			if (!yearData) {
   412→				if (year === endYear) {
   413→					purchasesArr.push(...(new Array(endDateDayNumber).fill(0) as number[]));
   414→				} else {
   415→					const daysInYear =
   416→						new Date(year, 11, 31).getDate() === 31 &&
   417→						new Date(year, 1, 29).getDate() === 29
   418→							? 366
   419→							: 365;
   420→					purchasesArr.push(...(new Array(daysInYear).fill(0) as number[]));
   421→				}
   422→			} else {
   423→				if (year === endYear) {
   424→					purchasesArr.push(...yearData.slice(0, endDateDayNumber));
   425→				} else {
   426→					purchasesArr.push(...yearData);
   427→				}
   428→			}
   429→		}
   430→
   431→		if (purchasesArr.length < totalExpectedDays) {
   432→			const missingDays = totalExpectedDays - purchasesArr.length;
   433→			purchasesArr.push(...(new Array(missingDays).fill(0) as number[]));
   434→		} else if (purchasesArr.length > totalExpectedDays) {
   435→			purchasesArr.splice(totalExpectedDays);
   436→		}
   437→
   438→		const smoothedPurchasesArr = MathematicalFunctions.exponentialSmoothing({
   439→			values: purchasesArr,
   440→			alpha: 0.1,
   441→		});
   442→
   443→		const harmonics = getHarmonicsByObservationsCount({
   444→			observations: smoothedPurchasesArr.length,
   445→		});
   446→
   447→		const changes = MathematicalFunctions.changePointDetection({
   448→			values: smoothedPurchasesArr,
   449→			significance: 0.02,
   450→			penalty: 0.1,
   451→			minSegmentLength: 40,
   452→		});
   453→
   454→		const yearlyComponent = calculateSeasonalComponent({
   455→			values: smoothedPurchasesArr,
   456→			period: 365,
   457→			harmonics,
   458→		});
   459→
   460→		const monthlyComponent = calculateSeasonalComponent({
   461→			values: smoothedPurchasesArr,
   462→			period: 30,
   463→			harmonics,
   464→		});
   465→
   466→		const weeklyComponent = calculateSeasonalComponent({
   467→			values: smoothedPurchasesArr,
   468→			period: 7,
   469→			harmonics,
   470→		});
   471→
   472→		const quarterlyComponent = calculateSeasonalComponent({
   473→			values: smoothedPurchasesArr,
   474→			period: 91,
   475→			harmonics,
   476→		});
   477→
   478→		const trendComponent = calculateTrendComponent({
   479→			values: smoothedPurchasesArr,
   480→			changePoints: changes.changePoints,
   481→			startDate: startDate,
   482→			endDate: endDate,
   483→		});
   484→
   485→		const residuals = purchasesArr.map((val, i) => {
   486→			const trend = trendComponent[i] ?? 0;
   487→			const yearly = yearlyComponent[i] ?? 0;
   488→			const monthly = monthlyComponent[i] ?? 0;
   489→			const weekly = weeklyComponent[i] ?? 0;
   490→			const quarterly = quarterlyComponent[i] ?? 0;
   491→			return val - (trend + yearly + monthly + weekly + quarterly);
   492→		});
   493→
   494→		const smoothedResidualsArr = MathematicalFunctions.exponentialSmoothing({
   495→			values: residuals,
   496→			alpha: 0.1,
   497→		});
   498→
   499→		const comprehensiveForecast = createComprehensiveForecast({
   500→			yearlyComponent,
   501→			monthlyComponent,
   502→			weeklyComponent,
   503→			quarterlyComponent,
   504→			trendComponent,
   505→			smoothedResidualsArr,
   506→			historicalLength: purchasesArr.length,
   507→			forecastDays,
   508→			endDate,
   509→			purchasesArr,
   510→		});
   511→
   512→		const historicalWindow = 14;
   513→		const historicalOrders = purchasesArr.slice(-historicalWindow);
   514→
   515→		const trendingScoreData = {
   516→			historicalOrders,
   517→			forecastedOrders: comprehensiveForecast.forecastValues,
   518→			trendComponent,
   519→		};
   520→
   521→		const trendingResult =
   522→			TrendingScoreCalculator.calculateTrendingScore(trendingScoreData);
   523→
   524→		const trendScore = trendingResult.trendScore;
   525→		let trendingReason = trendingResult.isSignificant
   526→			? `Statistical trend detected (p=${trendingResult.pValue.toFixed(3)}, effect=${trendingResult.effectSize.toFixed(2)})`
   527→			: 'No significant trend detected';
   528→
   529→		if (trendingResult.momentum > 0) {
   530→			trendingReason += ', accelerating';
   531→		} else if (trendingResult.momentum < 0) {
   532→			trendingReason += ', decelerating';
   533→		}
   534→
   535→		const forecastResult: CompleteForecastResult = {
   536→			style_id: styleId,
   537→			forecast_dates: comprehensiveForecast.forecastDates,
   538→			predicted_orders: comprehensiveForecast.forecastValues,
   539→			trend_score: Math.round(trendScore * 100) / 100,
   540→			trending_reason: trendingReason,
   541→			purchasesArr,
   542→			smoothedPurchasesArr,
   543→			yearlyComponent,
   544→			monthlyComponent,
   545→			weeklyComponent,
   546→			quarterlyComponent,
   547→			trendComponent,
   548→			smoothedResidualsArr,
   549→			comprehensiveForecast,
   550→			changes,
   551→			startDate,
   552→			endDate,
   553→		};
   554→
   555→		return forecastResult;
   556→	} catch {
   557→		return null;
   558→	}
   559→}
   560→
   561→function processBatch(data: WorkerData): WorkerResult {
   562→	try {
   563→		const results: CompleteForecastResult[] = [];
   564→
   565→		for (const item of data.batch) {
   566→			const result = forecastStyleTrend({
   567→				styleId: Number(item.styleId),
   568→				historicalData: item.historicalData,
   569→				startDate: data.startDate,
   570→				endDate: data.endDate,
   571→				forecastDays: data.forecastDays,
   572→			});
   573→
   574→			if (result && !Number.isNaN(result.trend_score)) {
   575→				results.push(result);
   576→			}
   577→		}
   578→
   579→		return { success: true, results };
   580→	} catch (error) {
   581→		return {
   582→			success: false,
   583→			error: error instanceof Error ? error.message : 'Unknown error',
   584→		};
   585→	}
   586→}
   587→
   588→if (parentPort) {
   589→	const data = workerData as WorkerData;
   590→	const result = processBatch(data);
   591→	parentPort.postMessage(result);
   592→}
