    18→
    19→	async getMonthlyOrderData({
    20→		startDate,
    21→		endDate,
    22→		limit = 100000,
    23→		offset = 0,
    24→	}: {
    25→		startDate: string;
    26→		endDate: string;
    27→		limit?: number;
    28→		offset?: number;
    29→	}): Promise<RedshiftTrendingItemDto[]> {
    30→		try {
    31→			this.logger.debug(
    32→				`Fetching order data from ${startDate} to ${endDate} with limit ${limit} and offset ${offset}`,
    33→			);
    34→
    35→			const query = this.knexRedshiftRead
    36→				.select(
    37→					'customer_orders.date_placed',
    38→					'product_information.style_id',
    39→					'product_information.style_name',
    40→					'product_information.style_sub_category_name',
    41→					'product_information.style_mega_category_name',
    42→					'product_information.style_uber_category_name',
    43→					this.knexRedshiftRead.raw(
    44→						'COUNT(DISTINCT customer_orders.customer_order_id) AS total_orders',
    45→					),
    46→				)
    47→				.from('general_use.customer_orders as customer_orders')
    48→				.leftJoin(
    49→					'factdata.order_items as order_items',
    50→					'customer_orders.customer_order_id',
    51→					'order_items.order_id',
    52→				)
    53→				.leftJoin(
    54→					'factdata.product_information as product_information',
    55→					'order_items.product_id',
    56→					'product_information.product_id',
    57→				)
    58→				.where('customer_orders.is_fix', false)
    59→				.where('customer_orders.is_undecorated', false)
    60→				.where('customer_orders.is_canceled', false)
    61→				.where('customer_orders.date_placed', '>=', startDate)
    62→				.where('customer_orders.date_placed', '<', endDate)
    63→				.groupBy(
    64→					'customer_orders.date_placed',
    65→					'product_information.style_id',
    66→					'product_information.style_name',
    67→					'product_information.style_sub_category_name',
    68→					'product_information.style_mega_category_name',
    69→					'product_information.style_uber_category_name',
    70→				)
    71→				.orderBy('customer_orders.date_placed', 'asc')
    72→				.limit(limit)
    73→				.offset(offset);
    74→
    75→			const results = await query;
    76→
    77→			if (results.length === 0) {
    78→				this.logger.debug('No orders found for the specified date range');
    79→				return [];
    80→			}
    81→
    82→			this.logger.debug(`Fetched ${results.length} order records`);
    83→
    84→			const validatedResults = await Promise.all(
    85→				results.map(async (result) => {
    86→					const dto = plainToInstance(RedshiftTrendingItemDto, result, {
    87→						enableImplicitConversion: true,
    88→						excludeExtraneousValues: false,
    89→					});
    90→					const errors = await validate(dto);
    91→					if (errors.length > 0) {
    92→						this.logger.error(
    93→							`Validation failed for order data: ${this.formatValidationErrors(errors)}`,
    94→						);
    95→						throw new Error(`Validation failed: ${this.formatValidationErrors(errors)}`);
    96→					}
    97→					return instanceToPlain<RedshiftTrendingItemDto>(dto) as RedshiftTrendingItemDto;
    98→				}),
    99→			);
   100→
   101→			return validatedResults;
   102→		} catch (error) {
   103→			this.logger.error(
   104→				`Failed to fetch order data for date range ${startDate} to ${endDate}: ${(error as Error).message}`,
   105→			);
   106→			throw error;
   107→		}
   108→	}
