   118→	}): Promise<RedshiftTrendingItemDto[]> {
   119→		try {
   120→			const allResults: RedshiftTrendingItemDto[] = [];
   121→
   122→			for (const month of months) {
   123→				const startDate = `${year}-${String(month).padStart(2, '0')}-01`;
   124→				const endDate =
   125→					month === 12
   126→						? `${year + 1}-01-01`
   127→						: `${year}-${String(month + 1).padStart(2, '0')}-01`;
   128→
   129→				let offset = 0;
   130→				let hasMore = true;
   131→
   132→				while (hasMore) {
   133→					const batch = await this.getMonthlyOrderData({
   134→						startDate,
