   138→					});
   139→
   140→					if (batch.length === 0) {
   141→						hasMore = false;
   142→					} else {
   143→						allResults.push(...batch);
   144→						offset += batchSize;
   145→
   146→						if (batch.length < batchSize) {
   147→							hasMore = false;
   148→						}
   149→					}
