   250→		const safeCount = Math.min(Math.max(count, 1), arr.length);
   251→		const copy = [...arr];
   252→		const result: T[] = [];
   253→		while (result.length < safeCount) {
   254→			const idx = Math.floor(Math.random() * copy.length);
   255→			const item = copy.splice(idx, 1)[0];
   256→			if (!item) result.push(item as T);
   257→		}
   258→		return result;
   259→	}
